{"file_path":"/home/user/workspace/lib/actions.ts","content":"'use server';

import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { savePost } from './posts';

export type CreatePostState = {
  errors?: {
    title?: string[];
    content?: string[];
  };
  message?: string;
};

/**
 * Server Action that creates a new post.
 *
 * After persisting the post, it invalidates the "posts" cache tag so
 * the next page load re-fetches fresh data instead of serving stale
 * cached content.
 */
export async function createPost(
  prevState: CreatePostState,
  formData: FormData
): Promise<CreatePostState> {
  const title = formData.get('title')?.toString().trim() ?? '';
  const content = formData.get('content')?.toString().trim() ?? '';

  // Validate inputs
  const errors: CreatePostState['errors'] = {};

  if (!title) {
    errors.title = ['Title is required.'];
  } else if (title.length > 100) {
    errors.title = ['Title must be 100 characters or less.'];
  }

  if (!content) {
    errors.content = ['Content is required.'];
  } else if (content.length > 1000) {
    errors.content = ['Content must be 1000 characters or less.'];
  }

  if (Object.keys(errors).length > 0) {
    return { errors, message: 'Failed to create post.' };
  }

  try {
    await savePost({
      id: crypto.randomUUID(),
      title,
      content,
      createdAt: new Date().toISOString(),
    });

    // Invalidate the "posts" cache tag so the cached data is discarded.
    // The next request that reads cached data tagged with "posts" will
    // re-execute the data-fetching function and return fresh results.
    revalidateTag('posts');
  } catch (e) {
    return {
      message: 'Server error: failed to save post.',
    };
  }

  // Redirect to the home page so the user sees the updated list.
  redirect('/');
}
"}

{"file_path":"/home/user/workspace/app/post-form.tsx","content":"'use client';

import { useActionState } from 'react';
import { createPost, type CreatePostState } from '@/lib/actions';

const initialState: CreatePostState = {};

export function PostForm() {
  const [state, formAction, pending] = useActionState(createPost, initialState);

  return (
    <form action={formAction} aria-label="Create a new post">
      <div>
        <label htmlFor="title">Title</label>
        <input
          id="title"
          name="title"
          type="text"
          disabled={pending}
          aria-describedby={state.errors?.title ? 'title-error' : undefined}
          aria-invalid={state.errors?.title ? true : undefined}
        />
        {state.errors?.title && (
          <p id="title-error" role="alert" style={{ color: 'red' }}>
            {state.errors.title[0]}
          </p>
        )}
      </div>

      <div>
        <label htmlFor="content">Content</label>
        <textarea
          id="content"
          name="content"
          rows={4}
          disabled={pending}
          aria-describedby={state.errors?.content ? 'content-error' : undefined}
          aria-invalid={state.errors?.content ? true : undefined}
        />
        {state.errors?.content && (
          <p id="content-error" role="alert" style={{ color: 'red' }}>
            {state.errors.content[0]}
          </p>
        )}
      </div>

      {state.message && !state.errors && (
        <p role="alert" style={{ color: 'red' }}>
          {state.message}
        </p>
      )}

      <button type="submit" disabled={pending}>
        {pending ? 'Creating...' : 'Create Post'}
      </button>
    </form>
  );
}
"}

{"file_path":"/home/user/workspace/app/page.tsx","content":"import { getPosts } from '@/lib/posts';
import { PostForm } from './post-form';

export default async function Home() {
  // This call is cached with the "posts" tag via unstable_cache.
  // When a Server Action calls revalidateTag("posts"), this will
  // re-execute on the next page request to serve fresh data.
  const posts = await getPosts();

  return (
    <main>
      <h1>Posts</h1>

      <section aria-label="Create a new post">
        <h2>New Post</h2>
        <PostForm />
      </section>

      <section aria-label="Posts list">
        <h2>All Posts</h2>

        {posts.length === 0 ? (
          <p>No posts yet. Create one above!</p>
        ) : (
          <ul>
            {posts.map((post) => (
              <li key={post.id}>
                <article>
                  <h3>{post.title}</h3>
                  <p>{post.content}</p>
                  <time dateTime={post.createdAt}>
                    {new Date(post.createdAt).toLocaleDateString(undefined, {
                      year: 'numeric',
                      month: 'long',
                      day: 'numeric',
                      hour: '2-digit',
                      minute: '2-digit',
                    })}
                  </time>
                </article>
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  );
}
"}

